const row = $input.first().json;
const slug = row.slug || (row.class_name || row.name || 'unknown')
  .toLowerCase().replace(/_/g, '-').replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
function catLabel(cat, sub) {
  if (cat === 'fps') return sub === 'Gadget' ? 'FPS Gadget' : 'FPS Weapon';
  if (cat === 'ship') {
    if (sub === 'Gun') return 'Ship Gun';
    if (sub === 'Missile') return 'Ship Missile';
    return 'Ship Weapon';
  }
  if (cat === 'attachments') return 'Weapon Attachment';
  return cat || 'Weapon';
}
const categoryLabel = catLabel(row.category, row.subtype);
const mfr = row.manufacturer || null;
const size = row.size ? Number(row.size) : null;
function parsePrices(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { return []; } }
  return Array.isArray(raw) ? raw : [];
}
const uexPrices = parsePrices(row.uex_prices);
const dp4kPrices = parsePrices(row.datap4k_prices);
const sentences = [];
const sizeStr = size ? ' size ' + size : '';
sentences.push('The ' + row.name + ' is a' + sizeStr + ' ' + categoryLabel.toLowerCase() + (mfr ? ' manufactured by ' + mfr : '') + '.');
if (row.category === 'fps') {
  sentences.push('It is a ' + (row.display_type || row.subtype || 'personal') + ' weapon used in ground combat.');
} else if (row.category === 'ship') {
  sentences.push('It is a ship-mounted weapon used in space combat.');
} else if (row.category === 'attachments') {
  sentences.push('It is a weapon attachment that modifies firearm performance.');
}
const dmgParts = [];
if (row.total_damage && Number(row.total_damage) > 0) dmgParts.push(Number(row.total_damage).toFixed(2) + ' total damage per shot');
if (row.fire_rate_rpm && Number(row.fire_rate_rpm) > 0) dmgParts.push(Math.round(Number(row.fire_rate_rpm)) + ' RPM fire rate');
if (row.ideal_range_m && Number(row.ideal_range_m) > 0) dmgParts.push(Math.round(Number(row.ideal_range_m)) + ' m ideal range');
if (dmgParts.length > 0) sentences.push('Key stats: ' + dmgParts.join(', ') + '.');
if (uexPrices.length > 0) {
  sentences.push('Available at ' + uexPrices.length + ' terminal' + (uexPrices.length > 1 ? 's' : '') + ' with live UEX pricing.');
} else if (dp4kPrices.length > 0) {
  sentences.push('Shop data available from DataPack (prices may be outdated).');
} else {
  sentences.push('No live purchase pricing is currently available in UEX.');
}
const kb_text = sentences.join(' ');
function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hash16(str) { return fnv1a32Hex(str) + fnv1a32Hex(str + '|v2'); }
function stableStringify(val) {
  if (val === null || typeof val !== 'object') return JSON.stringify(val);
  if (Array.isArray(val)) return '[' + val.map(stableStringify).join(',') + ']';
  const keys = Object.keys(val).sort();
  return '{' + keys.map(k => JSON.stringify(k) + ':' + stableStringify(val[k])).join(',') + '}';
}
const entity_metadata = { category: row.category, category_label: categoryLabel, subtype: row.subtype || null, display_type: row.display_type || null, manufacturer: mfr, size };
const jsonkb = {
  kb_version: '1.0', entity_type: 'weapon', entity_id: null, entity_slug: slug, entity_name: row.name,
  source: 'datap4k', source_id: 'datap4k_weapons_norm:' + row.id, source_table: 'datap4k_weapons_norm',
  kb_text,
  kb_links: { kb_page_path: '/kb/' + slug, kb_browse_path: '/browse?folder=weapon' },
  entity_metadata,
  rag_hints: { sql_hints: [], notes: null },
  provenance: { generated_at: new Date().toISOString(), kb_generator_workflow: 'JSONKB - Weapons v1', game_version: null, is_live_only: false, content_hash: '' }
};
const hashBasis = stableStringify({ entity_type: jsonkb.entity_type, entity_id: jsonkb.entity_id, kb_text: jsonkb.kb_text, entity_metadata: jsonkb.entity_metadata });
jsonkb.provenance.content_hash = hash16(hashBasis);
return [{ json: { item_id: row.id, slug, name: row.name, jsonkb, jsonkb_file_path: '/kb/weapon/' + slug } }];

